from typing import List, Dict, Any
from leann.api import PassageManager
from pathlib import Path
import json


def filter_passages_by_metadata_criteria(
    index_path: str,
    metadata_criteria: Dict[str, Any]
) -> List[Dict[str, Any]]:
    """Retrieve all passages from an index that match metadata criteria.

    Args:
        index_path: Path to the LEANN index directory or file
        metadata_criteria: Dictionary of metadata field-value pairs to match.
            Example: {"category": "tech", "rating": 5.0}
            All criteria must match (AND logic)

    Returns:
        List of passage dictionaries that match all criteria.
        Returns an empty list if no passages match or if the passages file
        does not exist.
    """
    # Normalize index path
    index_path_obj = Path(index_path)

    # Initialize PassageManager (this will typically locate the passages file)
    try:
        pm = PassageManager(index_path_obj)
    except Exception:
        # If PassageManager cannot be initialized, behave as if no passages file
        return []

    # Try to locate the passages data file from the PassageManager if possible.
    # Different versions of leann may store this path on different attributes,
    # so we defensively handle a few possibilities and fall back to a common name.
    passages_file: Path

    candidate_attrs = ["passages_path", "passages_file", "passage_path"]
    passages_file = None  # type: ignore[assignment]

    for attr in candidate_attrs:
        if hasattr(pm, attr):
            maybe_path = getattr(pm, attr)
            if isinstance(maybe_path, (str, Path)):
                passages_file = Path(maybe_path)
                break

    if passages_file is None:
        # Fallback: assume a default file name under the index path
        # Common patterns: passages.json or passages.jsonl
        for fname in ("passages.jsonl", "passages.json"):
            candidate = index_path_obj / fname
            if candidate.is_file():
                passages_file = candidate
                break

    # If still not found or file does not exist, return empty list
    if passages_file is None or not passages_file.is_file():
        return []

    matches: List[Dict[str, Any]] = []

    # Load passages from file; support both JSONL and JSON formats
    try:
        if passages_file.suffix.lower() == ".jsonl":
            with passages_file.open("r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        passage = json.loads(line)
                    except json.JSONDecodeError:
                        continue
                    if _passage_matches_metadata(passage, metadata_criteria):
                        matches.append(passage)
        else:
            # Assume standard JSON (list of passages)
            with passages_file.open("r", encoding="utf-8") as f:
                try:
                    data = json.load(f)
                except json.JSONDecodeError:
                    return []
                # Data might be a list of passages or a dict containing them
                if isinstance(data, list):
                    passages_iter = data
                elif isinstance(data, dict) and "passages" in data:
                    passages_iter = data["passages"]
                else:
                    passages_iter = []

                for passage in passages_iter:
                    if not isinstance(passage, dict):
                        continue
                    if _passage_matches_metadata(passage, metadata_criteria):
                        matches.append(passage)
    except FileNotFoundError:
        # If the file disappears between existence check and open
        return []

    return matches


def _passage_matches_metadata(
    passage: Dict[str, Any],
    metadata_criteria: Dict[str, Any]
) -> bool:
    """Check if a passage's metadata matches all criteria with exact equality."""
    if not metadata_criteria:
        # If no criteria are provided, consider that nothing matches
        return False

    metadata = passage.get("metadata") or passage.get("meta") or {}
    if not isinstance(metadata, dict):
        return False

    for key, value in metadata_criteria.items():
        if key not in metadata:
            return False
        if metadata[key] != value:
            return False
    return True
